export type ParsedDeployRoundInstruction<
  TProgram extends string = typeof ZINC_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    signer: TAccountMetas[0];
    round: TAccountMetas[1];
    config: TAccountMetas[2];
    miner: TAccountMetas[3];
    /** Lifetime deploy profile for the signing player. */
    playerProfile: TAccountMetas[4];
    /** Board singleton that tracks the currently enabled round, if any. */
    board: TAccountMetas[5];
    treasury: TAccountMetas[6];
    /** Program-owned lamport vault that accumulates stockpile SOL across cycles. */
    stockpileSolVault: TAccountMetas[7];
    /** Program-owned lamport vault that accumulates buyback SOL across deploys. */
    buybackSolVault: TAccountMetas[8];
    /** Current stockpile account that stays initialized across normal protocol operation. */
    stockpile: TAccountMetas[9];
    affiliate?: TAccountMetas[10] | undefined;
    affiliateProfile?: TAccountMetas[11] | undefined;
    systemProgram: TAccountMetas[12];
  };
  data: DeployRoundInstructionData;
};

export function parseDeployRoundInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedDeployRoundInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 13) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 13,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  const getNextOptionalAccount = () => {
    const accountMeta = getNextAccount();
    return accountMeta.address === ZINC_PROGRAM_ADDRESS
      ? undefined
      : accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      signer: getNextAccount(),
      round: getNextAccount(),
      config: getNextAccount(),
      miner: getNextAccount(),
      playerProfile: getNextAccount(),
      board: getNextAccount(),
      treasury: getNextAccount(),
      stockpileSolVault: getNextAccount(),
      buybackSolVault: getNextAccount(),
      stockpile: getNextAccount(),
      affiliate: getNextOptionalAccount(),
      affiliateProfile: getNextOptionalAccount(),
      systemProgram: getNextAccount(),
    },
    data: getDeployRoundInstructionDataDecoder().decode(instruction.data),
  };
}
